request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?holdingBin ?elem ?elemType ?elemName ?elemID WHERE {
  ?holdingBin vocab:NamedElement_name ?hbName . 
  FILTER(CONTAINS(LCASE(STR(?hbName)), LCASE("holding_bin"))) 
  ?holdingBin vocab:Element_ownedElement ?elem .
  ?elem rdf:type ?elemType .
  OPTIONAL { ?elem vocab:NamedElement_name ?elemName }
  OPTIONAL { ?elem vocab:MDObject_ID ?elemID }
}
LIMIT 50
